1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	const LOYALTY_RATE = 0.2;
4	const LOYALTY_THRESHOLD_YEARS = 2;
5	const BLOCK_SIZE = 3;
6	const BLOCK_BASE_PREMIUM = 60;
7	
8	const BASE_PREMIUM: Record<string, number> = {
9	  sword: 100,
10	  amulet: 60,
11	  staff: 80,
12	  potion: 40,
13	  rune: 25,
14	  moonstone: 25,
15	};
16	
17	const COMPONENT_TYPES = new Set(["rune", "moonstone"]);
18	
19	type Customer = { yearsWithMHPCO: number };
20	type Item = { type: string; cursed?: boolean; enchantment?: number };
21	const CURSE_RATE = 0.5;
22	const HIGH_ENCHANTMENT_RATE = 0.3;
23	const HIGH_ENCHANTMENT_THRESHOLD = 5;
24	type QuoteStep = { op: "quote"; items: Item[] };
25	type Input = { customer: Customer; steps: QuoteStep[] };
26	type QuoteResult = { premium: number };
27	
28	const countByType = (items: Item[]): Map<string, number> => {
29	  const counts = new Map<string, number>();
30	  for (const item of items) {
31	    counts.set(item.type, (counts.get(item.type) ?? 0) + 1);
32	  }
33	  return counts;
34	};
35	
36	const basePremiumForType = (type: string, count: number): number => {
37	  const unit = BASE_PREMIUM[type];
38	  if (COMPONENT_TYPES.has(type) && count === BLOCK_SIZE) {
39	    return BLOCK_BASE_PREMIUM;
40	  }
41	  return unit * count;
42	};
43	
44	const basePremium = (items: Item[]): number =>
45	  Array.from(countByType(items)).reduce(
46	    (total, [type, count]) => total + basePremiumForType(type, count),
47	    0,
48	  );
49	
50	// MHPCO always rounds premiums in its own favor (up).
51	const roundUpInMHPCOFavor = (amount: number): number => Math.ceil(amount);
52	
53	const isCursed = (item: Item): boolean => item.cursed === true;
54	const isHighlyEnchanted = (item: Item): boolean =>
55	  (item.enchantment ?? 0) >= HIGH_ENCHANTMENT_THRESHOLD;
56	
57	const itemSurcharge = (item: Item): number => {
58	  const unit = BASE_PREMIUM[item.type];
59	  const curseSurcharge = isCursed(item) ? unit * CURSE_RATE : 0;
60	  const enchantmentSurcharge = isHighlyEnchanted(item)
61	    ? unit * HIGH_ENCHANTMENT_RATE
62	    : 0;
63	  return curseSurcharge + enchantmentSurcharge;
64	};
65	
66	const sumItemSurcharges = (items: Item[]): number =>
67	  items.reduce((total, item) => total + itemSurcharge(item), 0);
68	
69	const isLoyalCustomer = (customer: Customer): boolean =>
70	  customer.yearsWithMHPCO >= LOYALTY_THRESHOLD_YEARS;
71	
72	const quotePremium = (step: QuoteStep, customer: Customer): QuoteResult => {
73	  const base = basePremium(step.items);
74	  const surcharges = sumItemSurcharges(step.items);
75	  const firstInsuranceSurcharge = base * FIRST_INSURANCE_RATE;
76	  const loyaltyDiscount = isLoyalCustomer(customer) ? base * LOYALTY_RATE : 0;
77	  return {
78	    premium: roundUpInMHPCOFavor(
79	      base + surcharges + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE,
80	    ),
81	  };
82	};
83	
84	export const run = (input: Input): { results: QuoteResult[] } => ({
85	  results: input.steps.map((step) => quotePremium(step, input.customer)),
86	});
